#include <bits/stdc++.h>
#define x first
#define y second
using namespace std;
typedef pair<int,int> pii;

const int N=1010,Q=1e5+10;

struct Node{
    int id,x,y;
}a[30*Q];

int n,m,q,cnt,dis[N];
vector<int> e[N],qu[N],s;
bitset<N> ans[Q];
queue<int> qq;

bool cmp(int x,int y){
    return a[x].y<a[y].y;
}

int main(){
    scanf("%d%d%d",&n,&m,&q);
    for(int i=1,u,v;i<=m;i++){
        scanf("%d%d",&u,&v);
        e[u].push_back(v);
        e[v].push_back(u);
    }
    for(int i=1,k;i<=q;i++){
        scanf("%d",&k);
        while(k--){
            cnt++;
            scanf("%d%d",&a[cnt].x,&a[cnt].y);
            a[cnt].id=i;
            qu[a[cnt].x].push_back(cnt);
        }
    }
    bitset<N> tmp;
    for(int i=1;i<=n;i++){
        sort(qu[i].begin(),qu[i].end(),cmp);
        memset(dis,-1,sizeof(dis));
        dis[i]=0;
        qq.push(i);
        while(qq.size()){
            int x=qq.front();
            qq.pop(),s.push_back(x);
            for(int y:e[x]){
                if(~dis[y])
                    continue;
                dis[y]=dis[x]+1;
                qq.push(y);
            }
        }
        tmp.reset();
        int j=0;
        for(int x:qu[i]){
            while(j<s.size() && dis[s[j]]<=a[x].y)
                tmp.set(s[j]),j++;
            ans[a[x].id]|=tmp;
        }
        s.clear();
    }
    for(int i=1;i<=q;i++)
        printf("%d\n",ans[i].count());
    return 0;
}
